#!/usr/bin/env python3"""Sweep stage2 UP/DOWN gate probabilities for a walk-forward run without retraining.This script reuses per-cycle model artifacts referenced by a walk-forward report andre-runs inference only on each cycle test window."""from __future__ import annotationsimport argparseimport itertoolsimport jsonimport sysfrom dataclasses import dataclassfrom pathlib import Pathimport joblibimport numpy as npimport pandas as pdPROJECT_ROOT = Path(__file__).resolve().parents[1]SCRIPT_DIR = Path(__file__).resolve().parentif str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))if str(SCRIPT_DIR) not in sys.path:    sys.path.insert(0, str(SCRIPT_DIR))try:    from data import DataLoaderexcept ModuleNotFoundError as exc:    raise ModuleNotFoundError(        "Could not import DataLoader. Ensure project root is on PYTHONPATH."    ) from exctry:    from training.image_trend_ml import (        LABEL_FLAT,        _compute_state_features_from_pred,        _prepare_ohlcv,        _resolve_directional_stops,        _resolve_directional_targets,        build_dataset,        directional_pnl_report,        flatten_tensors,        predict_two_stage_details,    )except ModuleNotFoundError:    # Fallback when training/ is not installed as a package.    from image_trend_ml import (        LABEL_FLAT,        _compute_state_features_from_pred,        _prepare_ohlcv,        _resolve_directional_stops,        _resolve_directional_targets,        build_dataset,        directional_pnl_report,        flatten_tensors,        predict_two_stage_details,    )@dataclassclass CycleInfer:    cycle_id: int    idx_slice: slice    x_aug: np.ndarray    m1: object    m2: object    stage1_gate: float    stage2_gate: floatdef _parse_grid(text: str) -> list[float]:    vals = [float(tok.strip()) for tok in text.split(",") if tok.strip()]    if not vals:        raise ValueError("Probability grid cannot be empty")    return valsdef _find_slice(ts: pd.DatetimeIndex, start_iso: str, end_iso: str) -> slice:    if len(start_iso) == 10 and len(end_iso) == 10:        sample_days = ts.tz_convert("UTC").normalize() if ts.tz is not None else ts.normalize()        if sample_days.tz is not None:            start_day = pd.Timestamp(start_iso, tz=sample_days.tz)            end_day = pd.Timestamp(end_iso, tz=sample_days.tz)        else:            start_day = pd.Timestamp(start_iso)            end_day = pd.Timestamp(end_iso)        s = int(sample_days.searchsorted(start_day, side="left"))        e = int(sample_days.searchsorted(end_day, side="right"))        if s >= e:            raise ValueError(f"Empty cycle slice for trading days {start_iso} -> {end_iso}")        return slice(s, e)    start = pd.Timestamp(start_iso)    end = pd.Timestamp(end_iso)    s = int(ts.searchsorted(start, side="left"))    e = int(ts.searchsorted(end, side="right"))    if s >= e:        raise ValueError(f"Empty cycle slice for {start_iso} -> {end_iso}")    return slice(s, e)def _cycle_slice_bounds(cycle: dict[str, object]) -> tuple[str, str]:    start_day = cycle.get("test_start")    end_day = cycle.get("test_end")    if start_day and end_day:        start_s = str(start_day)        end_s = str(end_day)        if len(start_s) == 10 and len(end_s) == 10:            return start_s, end_s    start = cycle.get("test_start_sample_ts", start_day)    end = cycle.get("test_end_sample_ts", end_day)    return str(start), str(end)def _get_stage2_gate_up(payload: dict, fallback: float) -> float:    val = payload.get("stage2_min_prob_up", fallback)    return float(fallback if val is None else val)def _get_stage2_gate_down(payload: dict, fallback: float) -> float:    val = payload.get("stage2_min_prob_down", fallback)    return float(fallback if val is None else val)def _resolve_cycle_model_path(report_path: Path, cycle_model_out: str) -> Path:    p = Path(cycle_model_out)    if p.is_absolute():        return p    candidate = (report_path.parent / p.name).resolve()    if candidate.exists():        return candidate    candidate = (PROJECT_ROOT / cycle_model_out).resolve()    if candidate.exists():        return candidate    return p.resolve()def _build_cycle_augmented_features(    x_raw: np.ndarray,    curr: np.ndarray,    entry_px: np.ndarray,    m1,    m2,    stage1_gate: float,    stage2_gate: float,    cfg: dict,    long_thr: float,    short_thr: float,    long_stop: float,    short_stop: float,    state_feature_names: list[str],    max_state_iters: int,) -> np.ndarray:    if not state_feature_names:        return x_raw    pred = np.full(len(x_raw), LABEL_FLAT, dtype=np.int64)    x_aug = x_raw    pred_history_len = int(cfg.get("pred_history_len", 150))    for _ in range(max_state_iters):        meta = _compute_state_features_from_pred(            pred,            curr,            entry_px,            adverse_limit=float(cfg["adverse_limit"]),            trend_threshold=float(cfg["trend_threshold"]),            long_target_threshold=long_thr,            short_target_threshold=short_thr,            long_adverse_limit=long_stop,            short_adverse_limit=short_stop,            pred_history_len=pred_history_len,        )        x_aug = np.hstack([x_raw, meta])        pm = predict_two_stage_details(            x_aug,            m1,            m2,            stage1_min_prob=stage1_gate,            stage2_min_prob=stage2_gate,            stage2_min_prob_up=_get_stage2_gate_up(cfg, fallback=stage2_gate),            stage2_min_prob_down=_get_stage2_gate_down(cfg, fallback=stage2_gate),            stage1_min_prob_1m=cfg.get("stage1_min_prob_1m"),            stage1_min_prob_15m=cfg.get("stage1_min_prob_15m"),            stage2_min_prob_1m=cfg.get("stage2_min_prob_1m"),            stage2_min_prob_15m=cfg.get("stage2_min_prob_15m"),        )        new_pred = pm["pred"]        if np.array_equal(new_pred, pred):            return x_aug        pred = new_pred    return x_augdef main() -> int:    ap = argparse.ArgumentParser(description="Sweep WF stage2 UP/DOWN gates without retraining")    ap.add_argument("--report-in", required=True, help="Existing walk-forward report JSON")    ap.add_argument(        "--long-probs",        dest="long_probs",        required=True,        help="Comma-separated stage2 UP/LONG gate values, e.g. 0.62,0.63,0.64",    )    ap.add_argument(        "--short-probs",        dest="short_probs",        required=True,        help="Comma-separated stage2 DOWN/SHORT gate values, e.g. 0.62,0.63,0.64",    )    ap.add_argument("--out-csv", default="training/wf_prob_sweep_no_retrain.csv")    ap.add_argument("--out-txt", default="training/wf_prob_sweep_no_retrain.txt")    ap.add_argument("--max-cycles", type=int, default=None, help="Optional cap for quick smoke tests")    ap.add_argument("--max-state-iters", type=int, default=3)    args = ap.parse_args()    report_path = Path(args.report_in)    report = json.loads(report_path.read_text())    cfg = dict(report["config"])    execution_semantics = dict(report.get("execution_semantics") or {})    if report.get("evaluation_mode") != "walk_forward":        raise ValueError("--report-in must be a walk-forward report")    long_grid = _parse_grid(args.long_probs)    short_grid = _parse_grid(args.short_probs)    raw = DataLoader().load_data(cfg["table"], start_date=cfg["start_date"], end_date=cfg["end_date"])    bars = _prepare_ohlcv(raw, cfg["timeframe"])    long_thr, short_thr = _resolve_directional_targets(        float(cfg["trend_threshold"]),        cfg.get("long_target_threshold"),        cfg.get("short_target_threshold"),    )    long_stop, short_stop = _resolve_directional_stops(        float(cfg["adverse_limit"]),        cfg.get("long_adverse_limit"),        cfg.get("short_adverse_limit"),    )    X_tensor, y, ts, curr_a, entry_a, fut_a, entry_ts_a, fut_ts_a, _, _ = build_dataset(        bars,        int(cfg["window"]),        float(cfg["min_window_range"]),        int(cfg["horizon"]),        float(cfg["trend_threshold"]),        float(cfg["adverse_limit"]),        long_target_threshold=cfg.get("long_target_threshold"),        short_target_threshold=cfg.get("short_target_threshold"),        long_adverse_limit=cfg.get("long_adverse_limit"),        short_adverse_limit=cfg.get("short_adverse_limit"),        min_15m_drop=float(cfg.get("min_15m_drop", 0.0) or 0.0),        min_15m_rise=float(cfg.get("min_15m_rise", 0.0) or 0.0),        window_15m=int(cfg.get("window_15m", 0) or 0),        apply_time_filter=not bool(cfg.get("disable_time_filter", False)),        use_15m_wick_features=bool(cfg.get("use_15m_wick_features", False)),        wick_feature_min_range=float(cfg.get("wick_feature_min_range", 40.0) or 40.0),        wick_feature_min_pct=float(cfg.get("wick_feature_min_pct", 35.0) or 35.0),        wick_feature_min_volume=float(cfg.get("wick_feature_min_volume", 3000.0) or 3000.0),    )    X_flat = flatten_tensors(X_tensor)    cycles: list[CycleInfer] = []    wf_cycles = list(report.get("walkforward_cycles", []))    if args.max_cycles is not None:        wf_cycles = wf_cycles[: max(0, args.max_cycles)]    for c in wf_cycles:        cycle_model_out = c.get("cycle_model_out")        if not cycle_model_out:            raise ValueError("Missing cycle_model_out in report. Re-run WF with cycle model saving enabled.")        bundle = joblib.load(_resolve_cycle_model_path(report_path, str(cycle_model_out)))        m1, m2 = bundle["stage1"], bundle["stage2"]        test_start_bound, test_end_bound = _cycle_slice_bounds(c)        sl = _find_slice(ts, test_start_bound, test_end_bound)        x_raw = X_flat[sl]        state_names = list(bundle.get("state_feature_names", []))        cycle_cfg = cfg.copy()        cycle_cfg.update(c.get("selected_config", {}))        x_aug = _build_cycle_augmented_features(            x_raw,            curr_a[sl],            entry_a[sl],            m1,            m2,            stage1_gate=float(c["selected_config"]["stage1_min_prob"]),            stage2_gate=float(c["selected_config"]["stage2_min_prob"]),            cfg=cycle_cfg,            long_thr=long_thr,            short_thr=short_thr,            long_stop=long_stop,            short_stop=short_stop,            state_feature_names=state_names,            max_state_iters=args.max_state_iters,        )        cycles.append(            CycleInfer(                cycle_id=int(c["cycle_id"]),                idx_slice=sl,                x_aug=x_aug,                m1=m1,                m2=m2,                stage1_gate=float(c["selected_config"]["stage1_min_prob"]),                stage2_gate=float(c["selected_config"]["stage2_min_prob"]),            )        )    rows: list[dict[str, float]] = []    for lp, sp in itertools.product(long_grid, short_grid):        y_pred_all = np.full(len(y), LABEL_FLAT, dtype=np.int64)        sig_all = np.zeros(len(y), dtype=np.float64)        mask = np.zeros(len(y), dtype=bool)        for cyc in cycles:            pm = predict_two_stage_details(                cyc.x_aug,                cyc.m1,                cyc.m2,                stage1_min_prob=cyc.stage1_gate,                stage2_min_prob=cyc.stage2_gate,                stage2_min_prob_up=float(lp),                stage2_min_prob_down=float(sp),                stage1_min_prob_1m=cfg.get("stage1_min_prob_1m"),                stage1_min_prob_15m=cfg.get("stage1_min_prob_15m"),                stage2_min_prob_1m=cfg.get("stage2_min_prob_1m"),                stage2_min_prob_15m=cfg.get("stage2_min_prob_15m"),            )            y_pred_all[cyc.idx_slice] = pm["pred"]            sig_all[cyc.idx_slice] = pm["signal_prob"]            mask[cyc.idx_slice] = True        idx = np.where(mask)[0]        pnl, _ = directional_pnl_report(            ts[idx],            entry_ts_a[idx],            fut_ts_a[idx],            y_pred_all[idx],            curr_a[idx],            entry_a[idx],            fut_a[idx],            signal_prob=sig_all[idx],            adverse_limit=float(cfg["adverse_limit"]),            long_adverse_limit=long_stop,            short_adverse_limit=short_stop,            allow_overlap=bool(cfg.get("allow_overlap_backtest", False)),            reverse_exit_prob=float(cfg.get("reverse_exit_prob", 0.7)),        )        all_stats = dict(pnl.get("all", {}))        rows.append(            {                "long_prob": float(lp),                "short_prob": float(sp),                "trades": int(all_stats.get("trades", pnl.get("trades", 0))),                "total_pnl": float(all_stats.get("total_pnl", pnl.get("total_pnl", 0.0))),                "profit_factor": float(all_stats.get("profit_factor") or 0.0),                "avg_day": float(all_stats.get("avg_day") or 0.0),                "trade_max_drawdown": float(all_stats.get("trade_max_drawdown", pnl.get("max_drawdown", 0.0))),                "daily_max_drawdown": float(all_stats.get("daily_max_drawdown") or 0.0),                "positive_days_pct": float(all_stats.get("positive_days_pct") or 0.0),                "win_rate_pct": float(all_stats.get("win_rate_pct") or 0.0),            }        )    out_df = pd.DataFrame(rows).sort_values(        by=["total_pnl", "profit_factor", "avg_day"], ascending=[False, False, False]    )    Path(args.out_csv).parent.mkdir(parents=True, exist_ok=True)    out_df.to_csv(args.out_csv, index=False)    top = out_df.head(10)    lines = [        f"report={report_path}",        f"cycles_used={len(cycles)}",        f"grid={len(long_grid)}x{len(short_grid)}={len(rows)} stage2_up x stage2_down",        f"entry_execution={execution_semantics.get('entry_execution', 'unknown')}",        f"signal_reference={execution_semantics.get('signal_reference', 'unknown')}",        "",        "Top 10 by total_pnl / profit_factor / avg_day:",        top.to_string(index=False),    ]    Path(args.out_txt).write_text("\n".join(lines) + "\n")    best = out_df.iloc[0]    print(        "best stage2 gates:",        f"up={best['long_prob']:.2f}",        f"down={best['short_prob']:.2f}",        f"pnl={best['total_pnl']:.2f}",        f"pf={best['profit_factor']:.3f}",        f"avg_day={best['avg_day']:.2f}",    )    print(f"saved csv: {args.out_csv}")    print(f"saved txt: {args.out_txt}")    return 0if __name__ == "__main__":    raise SystemExit(main())